import{_ as e,c as i,a2 as r,o as l}from"./chunks/framework.trnLO_3_.js";const s=JSON.parse('{"title":"生物进化","description":"","frontmatter":{},"headers":[],"relativePath":"kaoshi/biology.md","filePath":"kaoshi/biology.md","lastUpdated":1735793351000}'),t={name:"kaoshi/biology.md"};function o(m,a,n,p,g,h){return l(),i("div",null,a[0]||(a[0]=[r('<h1 id="生物进化" tabindex="-1">生物进化 <a class="header-anchor" href="#生物进化" aria-label="Permalink to &quot;生物进化&quot;">​</a></h1><h2 id="生物有共有的祖先" tabindex="-1">生物有共有的祖先 <a class="header-anchor" href="#生物有共有的祖先" aria-label="Permalink to &quot;生物有共有的祖先&quot;">​</a></h2><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/10/34131_image-20241231102147079.png" alt="image-20241231102147079" loading="lazy"></p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/10/75716_image-20241231102533246.png" alt="image-20241231102533246" style="zoom:50%;"><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/10/18363_image-20241231102905242.png" alt="image-20241231102905242" loading="lazy"></p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/16/32523_image-20241231165317298.png" alt="image-20241231165317298" loading="lazy"></p><h2 id="自然选择与适应的形成" tabindex="-1">自然选择与适应的形成 <a class="header-anchor" href="#自然选择与适应的形成" aria-label="Permalink to &quot;自然选择与适应的形成&quot;">​</a></h2><h3 id="拉马克-用进废退、获得性遗传" tabindex="-1">拉马克：用进废退、获得性遗传 <a class="header-anchor" href="#拉马克-用进废退、获得性遗传" aria-label="Permalink to &quot;拉马克：用进废退、获得性遗传&quot;">​</a></h3><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/10/85099_image-20241231103736338.png" alt="image-20241231103736338" loading="lazy"></p><p>如长颈鹿脖子，盲鱼眼睛，蜂鸟采蜜</p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/10/79486_image-20241231104540878.png" alt="image-20241231104540878" loading="lazy"></p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/16/47899_image-20241231165459396.png" alt="image-20241231165459396" loading="lazy"></p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/16/8734_image-20241231165630780.png" alt="image-20241231165630780" loading="lazy"></p><h4 id="_19世纪自然科学三大发现" tabindex="-1">19世纪自然科学三大发现 <a class="header-anchor" href="#_19世纪自然科学三大发现" aria-label="Permalink to &quot;19世纪自然科学三大发现&quot;">​</a></h4><h5 id="_1、细胞学说" tabindex="-1">1、细胞学说 <a class="header-anchor" href="#_1、细胞学说" aria-label="Permalink to &quot;1、细胞学说&quot;">​</a></h5><p><a href="https://baike.baidu.com/item/%E7%BB%86%E8%83%9E%E5%AD%A6%E8%AF%B4/1980415?fromModule=lemma_inlink" target="_blank" rel="noreferrer">细胞学说</a>细胞是动植物结构和<a href="https://baike.baidu.com/item/%E7%94%9F%E5%91%BD%E6%B4%BB%E5%8A%A8/8609523?fromModule=lemma_inlink" target="_blank" rel="noreferrer">生命活动</a>的<a href="https://baike.baidu.com/item/%E5%9F%BA%E6%9C%AC%E5%8D%95%E4%BD%8D/10189558?fromModule=lemma_inlink" target="_blank" rel="noreferrer">基本单位</a>，是1838~1839年间由德国<a href="https://baike.baidu.com/item/%E6%A4%8D%E7%89%A9%E5%AD%A6%E5%AE%B6/1244092?fromModule=lemma_inlink" target="_blank" rel="noreferrer">植物学家</a><a href="https://baike.baidu.com/item/%E6%96%BD%E8%8E%B1%E7%99%BB/383414?fromModule=lemma_inlink" target="_blank" rel="noreferrer">施莱登</a>(Matthias Jakob Schleiden)和<a href="https://baike.baidu.com/item/%E5%8A%A8%E7%89%A9%E5%AD%A6%E5%AE%B6/1244200?fromModule=lemma_inlink" target="_blank" rel="noreferrer">动物学家</a><a href="https://baike.baidu.com/item/%E6%96%BD%E6%97%BA/10866066?fromModule=lemma_inlink" target="_blank" rel="noreferrer">施旺</a>(Theodor Schwann)最早提出；</p><p>直到1858年，德国魏尔肖提出细胞通过分裂产生新细胞的观点，才较完善。它是关于生物<a href="https://baike.baidu.com/item/%E6%9C%89%E6%9C%BA%E4%BD%93/6786167?fromModule=lemma_inlink" target="_blank" rel="noreferrer">有机体</a>组成的学说。</p><p>细胞学说论证了整个生物界在结构上的统一性，以及在进化上的<a href="https://baike.baidu.com/item/%E5%85%B1%E5%90%8C%E8%B5%B7%E6%BA%90/1372674?fromModule=lemma_inlink" target="_blank" rel="noreferrer">共同起源</a>。细胞学说揭示了细胞的统一性。这一学说的建立推动了生物学的发展，并为<a href="https://baike.baidu.com/item/%E8%BE%A9%E8%AF%81%E5%94%AF%E7%89%A9%E8%AE%BA/9203571?fromModule=lemma_inlink" target="_blank" rel="noreferrer">辩证唯物论</a>提供了重要的自然科学依据。</p><h5 id="_2、能量守恒和转换定律" tabindex="-1">2、能量守恒和转换定律 <a class="header-anchor" href="#_2、能量守恒和转换定律" aria-label="Permalink to &quot;2、能量守恒和转换定律&quot;">​</a></h5><p><a href="https://baike.baidu.com/item/%E8%83%BD%E9%87%8F%E5%AE%88%E6%81%92%E5%8F%8A%E8%BD%AC%E5%8C%96%E5%AE%9A%E5%BE%8B/19165113?fromModule=lemma_inlink" target="_blank" rel="noreferrer">能量守恒及转化定律</a>指的是自然界中一切物质都具有能量。能量有各种不同的表现形式，并能从一种形式转化为另一种形式(包括物质和能量的相对论式转换)，从一个物体传递给另一个物体。</p><h5 id="_3、自然选择学说" tabindex="-1">3、自然选择学说 <a class="header-anchor" href="#_3、自然选择学说" aria-label="Permalink to &quot;3、自然选择学说&quot;">​</a></h5><p>自然选择说是由达尔文提出的关于<a href="https://baike.baidu.com/item/%E7%94%9F%E7%89%A9%E8%BF%9B%E5%8C%96/3311428?fromModule=lemma_inlink" target="_blank" rel="noreferrer">生物进化</a>机理的一种学说。达尔文认为，在变化着的生活条件下，生物几乎都表现出<a href="https://baike.baidu.com/item/%E4%B8%AA%E4%BD%93%E5%B7%AE%E5%BC%82/10045292?fromModule=lemma_inlink" target="_blank" rel="noreferrer">个体差异</a>，并有<a href="https://baike.baidu.com/item/%E8%BF%87%E5%BA%A6%E7%B9%81%E6%AE%96/2037564?fromModule=lemma_inlink" target="_blank" rel="noreferrer">过度繁殖</a>的倾向;在<a href="https://baike.baidu.com/item/%E7%94%9F%E5%AD%98%E6%96%97%E4%BA%89/1278026?fromModule=lemma_inlink" target="_blank" rel="noreferrer">生存斗争</a>过程中，具有<a href="https://baike.baidu.com/item/%E6%9C%89%E5%88%A9%E5%8F%98%E5%BC%82/915646?fromModule=lemma_inlink" target="_blank" rel="noreferrer">有利变异</a>的个体能生存下来并繁殖后代，具有不利变异的个体则逐渐被淘汰。</p><p>此种汰劣留良或适者生存的原理，达尔文称之为自然选择。他认为应用自然选择原理可以说明<a href="https://baike.baidu.com/item/%E7%94%9F%E7%89%A9%E7%95%8C/10918824?fromModule=lemma_inlink" target="_blank" rel="noreferrer">生物界</a>的适应性、多样性和物种的起源。</p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/10/91039_image-20241231105527212.png" alt="image-20241231105527212" loading="lazy"></p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/10/55351_image-20241231105700379.png" alt="image-20241231105700379" loading="lazy"></p><h2 id="种群基因组成的变化" tabindex="-1">种群基因组成的变化 <a class="header-anchor" href="#种群基因组成的变化" aria-label="Permalink to &quot;种群基因组成的变化&quot;">​</a></h2><p>种群不是数量的简单叠加，重要的是为了繁衍后代，属于繁殖单位。</p><p>海洋中的鱼类不是种群</p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/11/31147_image-20241231111959103.png" alt="image-20241231111959103" loading="lazy"></p><p>等位基因：是指位于一对<a href="https://baike.baidu.com/item/%E5%90%8C%E6%BA%90%E6%9F%93%E8%89%B2%E4%BD%93/4096998?fromModule=lemma_inlink" target="_blank" rel="noreferrer">同源染色体</a>相同位置上控制同一性状不同形态的<a href="https://baike.baidu.com/item/%E5%9F%BA%E5%9B%A0/227875?fromModule=lemma_inlink" target="_blank" rel="noreferrer">基因</a></p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/11/30045_image-20241231115645955.png" alt="image-20241231115645955" loading="lazy"></p><h4 id="基因突变-指基因在结构上发生碱基对组成或排列顺序的改变" tabindex="-1">基因突变：指基因在结构上发生碱基对组成或排列顺序的改变 <a class="header-anchor" href="#基因突变-指基因在结构上发生碱基对组成或排列顺序的改变" aria-label="Permalink to &quot;基因突变：指基因在结构上发生碱基对组成或排列顺序的改变&quot;">​</a></h4><p><strong>1、发生原因</strong></p><ul><li>自发突变：在自然状态下，由于DNA复制过程中的偶然错误而发生，并且随着细胞分裂次数的增加，这种自发突变的可能性也会累积。</li><li>诱发突变：物理因素如紫外线、X射线等辐射能够破坏DNA的正常结构，影响其复制和转录等功能，进而引发突变；化学因素如亚硝酸盐、碱基类似物等可以使碱基发生化学修饰，导致碱基配对错误；某些病毒等生物因子也可能诱导基因突变。</li></ul><p><strong>2、突变类型</strong></p><ul><li>碱基替换：包括转换和颠换，转换是指嘌呤与嘌呤之间、嘧啶与嘧啶之间的替换，如A-G或者T-C；颠换则是嘌呤与嘧啶之间的替换，像A-T。</li><li>移码突变：当DNA分子中插入或缺失一个或几个非3倍数的碱基对时，会使基因的读码框发生改变。</li><li>缺失和重复：大片段的缺失可能会使基因功能完全丧失，而基因的重复则可能会增加基因产物的量或者导致基因功能的异常。</li></ul><p><strong>3、突变影响</strong></p><ul><li>有害突变：大多数基因突变是有害的，例如人类的许多遗传病都是由基因突变引起的。</li><li>有益突变：少数基因突变可能是有益的，在生物进化过程中，有益突变可能使生物个体更好地适应环境。</li></ul><p>基因突变具有重要意义，是生物变异的根本来源，为进化提供丰富原材料，虽多数突变有害，但少数有益突变可使生物更好适应环境。在自然选择作用下，有利突变基因频率增加，推动生物不断演变，使其能在多变的环境中生存和发展，展现出生命的多样与适应性。</p><p><strong>基因突变的检测方法</strong></p><ul><li>从分子层面来看，聚合酶链式反应即PCR及其相关技术应用广泛，如PCR-单链构象多态性分析，通过扩增DNA片段后分析其单链构象差异来检测突变。DNA测序技术能直接确定基因的碱基序列，精准检测突变位点，是基因突变检测的金标准。</li><li>在蛋白质水平，蛋白质免疫印迹等方法可检测由于基因突变导致的蛋白质表达或结构变化，生物芯片技术能同时对大量基因进行检测，高效筛选出突变基因，为疾病诊断和研究等提供有力支持，更深入地了解基因突变相关情况，在医学诊断、遗传研究等领域发挥着关键作用。</li></ul><h4 id="色体变异通常有缺失、重复、倒位、易位和非整倍性等类型。" tabindex="-1">色体变异通常有缺失、重复、倒位、易位和非整倍性等类型。 <a class="header-anchor" href="#色体变异通常有缺失、重复、倒位、易位和非整倍性等类型。" aria-label="Permalink to &quot;色体变异通常有缺失、重复、倒位、易位和非整倍性等类型。&quot;">​</a></h4><p>1.缺失：指的是染色体上某一部分的丢失，这可能导致基因表达异常或功能丧失，从而引发疾病。</p><p>2.重复：染色体上某一段DNA序列出现额外的拷贝，可能导致基因表达量增加，影响细胞功能。</p><p>3.倒位：染色体上的一段DNA序列发生方向性的翻转，可能改变基因的调控区域，影响基因表达。</p><p>4.易位：染色体上的一段DNA序列转移到另一条非同源染色体上，可能导致基因表达位置改变，影响基因功能。</p><p>5.非整倍性：细胞内染色体数目异常，如三体综合征，即某条染色体出现三条，这可能导致严重的发育障碍。</p><h4 id="基因突变和染色体变异主要区别在于是否可以被显微镜观察到。" tabindex="-1">基因突变和染色体变异主要区别在于是否可以被显微镜观察到。 <a class="header-anchor" href="#基因突变和染色体变异主要区别在于是否可以被显微镜观察到。" aria-label="Permalink to &quot;基因突变和染色体变异主要区别在于是否可以被显微镜观察到。&quot;">​</a></h4><p>区别1:</p><p>染色体变异是可以通过显微镜观察到的，染色体在做加减分裂或排列的时候出现了异常，例如染色体多一条或少一条染色体的长臂或短臂缺失或重复染色体的方向导致或染色体的长臂短臂连接出现问题的。</p><p>而基因突变没有办法具体观察到的，基因是染色体的一部分，发生突变时是在染色体的一个节点上显现的。</p><p>区别2:</p><p>基因突变一般是在结构上发生了顺序的改变，还有可能是因为各种物理射线的影响，或者是某些化学物质，比如农药、生物碱、黄曲霉素等，都容易导致基因突变。基因突变一般发生在DNA复制的时期，但是不是所有的基因突变都会对身体造成伤害。</p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/15/50494_image-20241231151914602.png" alt="image-20241231151914602" loading="lazy"></p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/15/27059_image-20241231155103842.png" alt="image-20241231155103842" loading="lazy"></p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/16/91889_image-20241231165843549.png" alt="image-20241231165843549" loading="lazy"></p><h2 id="基因频率计算" tabindex="-1">基因频率计算 <a class="header-anchor" href="#基因频率计算" aria-label="Permalink to &quot;基因频率计算&quot;">​</a></h2><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/15/30292_image-20241231155910471.png" alt="image-20241231155910471" loading="lazy"></p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/16/36656_image-20241231161355336.png" alt="image-20241231161355336" loading="lazy"></p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/16/56102_image-20241231162721115.png" alt="image-20241231162721115" loading="lazy"></p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/23/46577_62822_image-20241231164259334.png" alt="image-20241231164259334" loading="lazy"></p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/23/92981_image-20241231165040178.png" alt="image-20241231165040178" loading="lazy"></p><h2 id="高考题" tabindex="-1">高考题 <a class="header-anchor" href="#高考题" aria-label="Permalink to &quot;高考题&quot;">​</a></h2><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/23/98046_image-20241231170019279.png" alt="image-20241231170019279" loading="lazy"></p><p><img src="https://gitlab.com/loveagri/pic/-/raw/main/2024-12-31/23/64849_68097_image-20241231170133807.png" alt="image-20241231170133807" loading="lazy"></p>',65)]))}const d=e(t,[["render",o]]);export{s as __pageData,d as default};
